import React, { useEffect, useState } from 'react';
import api from '../api';
import { Patient } from '../types';

const PatientList: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>([]);
    const [firstName, setFirstName] = useState('');
    const [lastName, setLastName] = useState('');

    useEffect(() => {
        api.get('patients/').then(res => setPatients(res.data));
    }, []);

    const handleAdd = async () => {
        const newPatient = { first_name: firstName, last_name: lastName };
        await api.post('patients/', newPatient);
        window.location.reload(); // Refresh para makita ang bag-o
    };

    return (
        <div className="p-4 border">
            <h3>Patient Registry</h3>
            <input placeholder="First Name" onChange={e => setFirstName(e.target.value)} className="border m-1" />
            <input placeholder="Last Name" onChange={e => setLastName(e.target.value)} className="border m-1" />
            <button onClick={handleAdd} className="bg-green-500 text-white p-1">Register</button>
            <ul>
                {patients.map(p => <li key={p.patient_id}>{p.first_name} {p.last_name}</li>)}
            </ul>
        </div>
    );
};
export default PatientList;
